&lt;h2 dir=&quot;ltr&quot; style=&quot;line-height:1.38;margin-top:18pt;margin-bottom:4pt;&quot;&gt;&lt;span style=&quot;font-size:17pt;font-family:Arial, sans-serif;color:#000000;background-color:transparent;font-weight:bold;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre-wrap;&quot;&gt;Những c&acirc;u hỏi thường gặp về an to&agrave;n khi Trekking C&aacute;t B&agrave;&lt;/span&gt;&lt;/h2&gt;
